const emails = $input.all();

function sanitize(text) {
  if (!text) return '';
text = text.replace(/\b(otp|code|pin|verify|verification|token|passcode)\b[\s\S]{0,40}?\b(\d{4,8})\b/gi, '$1: [CODE HIDDEN]');
  text = text.replace(/(password|passwd|pwd|pass|secret|pin)[\s\S]{0,30}?[:\-=]\s*\S+/gi, '$1: [PASSWORD HIDDEN]');
  text = text.replace(/\b(?:\d[ -]?){13,19}\b/g, '[CARD NUMBER HIDDEN]');
  text = text.replace(/(token|api[_\s]?key|secret[_\s]?key|access[_\s]?key|auth[_\s]?key|bearer)[\s\S]{0,30}?[:\-=]\s*\S+/gi, '$1: [KEY HIDDEN]');
  return text.trim();
}

const emailList = emails.map((item, index) => {
  const email = item.json;
  return {
    index: index + 1,
    subject: sanitize(email.Subject || '(No Subject)'),
    from: email.From || '(Unknown)',
    snippet: sanitize(email.snippet || '')
  };
});

return [{ json: { totalEmails: emailList.length, emailSummaryText: emailList.map(e => `From: ${e.from}\nSub: ${e.subject}\nSnippet: ${e.snippet}`).join('\n\n') } }];

const today = new Date().toLocaleDateString(undefined, {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

const emptyMessage = "Inbox Zero! No primary emails requiring your attention today.";

return {
  json: {
    summary: emptyMessage,
    today,
    docTitle: `Emails Overview - ${today}`,
    whatsappMessage: `📧 *Daily Emails Overview*\n📅 ${today}\n\n${emptyMessage}`
  }
};
